function parsePricing(pricing) {
  if (!pricing) return { low: null, high: null, uncertain: true };
  const p = pricing.toLowerCase();
  if (p.includes("free") && !p.includes("$")) return { low: 0, high: 0, uncertain: false };
  if (p.includes("contact") || p.includes("call ahead") || p.includes("varies") ||
      p.includes("package") || p.includes("check") || p.includes("scheduled") ||
      p.includes("appointment") || p.includes("guided trip")) return { low: null, high: null, uncertain: true };
  const nums = [...pricing.matchAll(/\$([0-9]+(?:\.[0-9]+)?)/g)].map(m => parseFloat(m[1]));
  if (nums.length === 0) return { low: null, high: null, uncertain: true };
  return { low: Math.min(...nums), high: Math.max(...nums), uncertain: false };
}

