function MineralMapComponent({ mines, region }) {
  const mapRef = useRef(null);
  const leafletMapRef = useRef(null);

  useEffect(() => {
    if (!leafletMapRef.current) return;
    if (region === "WLD") leafletMapRef.current.flyTo([20, 0], 1, { duration: 0.8 });
    else leafletMapRef.current.flyTo([39.5, -98.35], 4, { duration: 0.8 });
  }, [region]);

  useEffect(() => {
    if (leafletMapRef.current) return;
    const initCenter = region === "WLD" ? [20, 0] : [39.5, -98.35];
    const initZoom = region === "WLD" ? 1 : 4;
    loadLeafletOnce().then(L => {
      const map = L.map(mapRef.current, { center: initCenter, zoom: initZoom });
      L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", { attribution: "(c) OpenStreetMap", maxZoom: 18 }).addTo(map);
      leafletMapRef.current = map;

      // Draw state outlines first as a neutral base
      L.geoJSON(US_STATES_GEOJSON, {
        style: { fillColor: "#f8fafc", fillOpacity: 0.6, color: "#cbd5e1", weight: 1 },
        interactive: false
      }).addTo(map);

      // Draw geological zones - non-interactive so mine dots are always clickable
      const zoneLayer = L.geoJSON(GEO_ZONES_GEOJSON, {
        style: feature => ({
          fillColor: getCategoryColor(feature.properties.cat),
          fillOpacity: 0.35,
          color: "#ffffff",
          weight: 0.5
        }),
        interactive: false
      }).addTo(map);

      // Draw crisp state borders on top
      L.geoJSON(US_STATES_GEOJSON, {
        style: { fill: false, color: "#374151", weight: 1.5, opacity: 0.6 },
        interactive: false
      }).addTo(map);

      // Draw mine dots on top - larger so they're easy to click
      for (const mine of mines) {
        const cats = classifyGems(mine.gems);
        L.circleMarker([mine.lat, mine.lng], {
          radius: 7, fillColor: getCategoryColor(cats[0]),
          color: "#1e293b", weight: 2, fillOpacity: 1.0
        }).addTo(map).bindTooltip("<b>" + mine.name + "</b><br>" + cats.join(", "), { opacity: 0.95 });
      }

      // Map click: find all geological zones at clicked point and show info panel
      const infoDiv = L.DomUtil.create("div");
      infoDiv.style.cssText = "position:absolute;bottom:16px;right:10px;background:rgba(255,255,255,0.97);border:1px solid #d1d5db;border-radius:8px;padding:10px 14px;font-size:11px;z-index:999;max-width:220px;display:none;box-shadow:0 2px 12px rgba(0,0,0,0.15);";
      map.getContainer().appendChild(infoDiv);

      map.on("click", function(e) {
        const pt = e.latlng;
        const matches = [];
        GEO_ZONES_GEOJSON.features.forEach(feat => {
          // Simple point-in-polygon check using Leaflet bounds as prefilter
          const layer = L.geoJSON(feat);
          const bounds = layer.getBounds();
          if (!bounds.contains(pt)) return;
          // Check each polygon ring
          try {
            const coords = feat.geometry.coordinates;
            const geomType = feat.geometry.type;
            const rings = geomType === "Polygon" ? [coords[0]] :
                          geomType === "MultiPolygon" ? coords.map(p => p[0]) : [];
            for (const ring of rings) {
              if (pointInRing(pt.lng, pt.lat, ring)) {
                matches.push(feat.properties);
                break;
              }
            }
          } catch(e) {}
        });

        if (matches.length === 0) { infoDiv.style.display = "none"; return; }
        infoDiv.style.display = "block";
        infoDiv.innerHTML = "<b style='font-size:12px;color:#374151'>Geology at this point:</b><br><br>" +
          matches.map(m =>
            "<span style='display:inline-block;width:10px;height:10px;border-radius:2px;background:" +
            getCategoryColor(m.cat) + ";margin-right:5px;vertical-align:middle;'></span>" +
            "<b>" + m.cat + "</b><br><span style='color:#6b7280;font-size:10px;margin-left:15px;'>" + m.name + "</span>"
          ).join("<br>") +
          "<br><br><span style='font-size:9px;color:#9ca3af;cursor:pointer;' onclick='this.parentNode.style.display=\"none\"'>click to dismiss</span>";
      });

      // Ray-casting point-in-polygon
      function pointInRing(x, y, ring) {
        let inside = false;
        for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
          const xi = ring[i][0], yi = ring[i][1];
          const xj = ring[j][0], yj = ring[j][1];
          if (((yi > y) !== (yj > y)) && (x < (xj - xi) * (y - yi) / (yj - yi) + xi)) inside = !inside;
        }
        return inside;
      }
    });
  }, []);

  return <div ref={mapRef} style={{ width: "100%", height: "100%" }} />;
}


export default function GemMineMap() {
  const [viewMode, setViewMode] = useState("dig");
  const [region, setRegion] = useState("US");
  const [legendOpen, setLegendOpen] = useState(true);
  const [visited, setVisited] = useState(new Set());
  const [selected, setSelected] = useState(null);
  const [searchMode, setSearchMode] = useState("state");
  const [stateFilter, setStateFilter] = useState("ALL");
  const [gemSearch, setGemSearch] = useState("");
  const [priceMin, setPriceMin] = useState("");
  const [priceMax, setPriceMax] = useState("");
  const [includeUncertain, setIncludeUncertain] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [loaded, setLoaded] = useState(false);
  const [typeFilters, setTypeFilters] = useState({ dig: true, fossil: true, publicLand: true, shop: true });
  const [showVisitedBreakdown, setShowVisitedBreakdown] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [showHelp, setShowHelp] = useState(false);
  const [showViews, setShowViews] = useState(false);
  const [nearbyMode, setNearbyMode] = useState(false);
  const [userLocation, setUserLocation] = useState(null);
  const [locationError, setLocationError] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const r = await window.storage?.get("gem-visited-v4");
        if (r?.value) setVisited(new Set(JSON.parse(r.value)));
      } catch (e) {}
      setLoaded(true);
    })();
  }, []);

  useEffect(() => {
    if (!loaded) return;
    window.storage?.set("gem-visited-v4", JSON.stringify([...visited])).catch(() => {});
  }, [visited, loaded]);

  const toggleVisited = id => setVisited(prev => {
    const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n;
  });

  const filtered = MINES.filter(m => {
    // Type filter
    const mType = m.type === "fossil" ? "fossil" : m.type === "shop" ? "shop" : m.public ? "publicLand" : "dig";
    if (!typeFilters[mType]) return false;

    if (searchMode === "state") {
      if (region === "WLD") {
        if (stateFilter === "ALL") return true;
        if (stateFilter === "United States") return !m.country;
        return m.country === stateFilter;
      }
      return stateFilter === "ALL" || m.state === stateFilter;
    }
    if (searchMode === "country") {
      if (stateFilter === "ALL") return true;
      if (stateFilter === "United States") return !m.country;
      return m.country === stateFilter;
    }
    if (searchMode === "gem") {
      const q = gemSearch.toLowerCase().trim();
      if (!q) return true;
      return m.gems.some(g => g.toLowerCase().includes(q)) || m.name.toLowerCase().includes(q) || (m.note && m.note.toLowerCase().includes(q)) || (m.country && m.country.toLowerCase().includes(q));
    }
    if (searchMode === "price") {
      const { low, high, uncertain } = parsePricing(m.pricing);
      if (uncertain || low === null) return includeUncertain;
      const min = priceMin === "" ? 0 : parseFloat(priceMin);
      const max = priceMax === "" ? Infinity : parseFloat(priceMax);
      return high <= max && high >= min;
    }
    return true;
  });

  const haversine = (lat1, lng1, lat2, lng2) => {
    const R = 3958.8; // miles
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLng = (lng2 - lng1) * Math.PI / 180;
    const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180) * Math.cos(lat2*Math.PI/180) * Math.sin(dLng/2)**2;
    return R * 2 * Math.asin(Math.sqrt(a));
  };

  const handleNearby = () => {
    if (nearbyMode) { setNearbyMode(false); setUserLocation(null); return; }
    navigator.geolocation.getCurrentPosition(
      pos => { setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }); setNearbyMode(true); setLocationError(null); },
      () => setLocationError("Location access denied")
    );
  };

  const exportVisited = () => {
    const lines = ["Name,State/Country,Gems,Type"];
    MINES.filter(m => visited.has(m.id)).forEach(m => {
      const region = m.country || STATE_NAMES[m.state] || m.state || "";
      const type = m.type === "fossil" ? "Fossil" : m.type === "shop" ? "Shop" : m.public ? "Public Land" : "Fee Dig";
      lines.push([m.name, region, m.gems.join("|"), type].map(v => '"' + v.replace(/"/g, '""') + '"').join(","));
    });
    const blob = new Blob([lines.join("\n")], { type: "text/csv" });
    const a = document.createElement("a"); a.href = URL.createObjectURL(blob);
    a.download = "visited_sites.csv"; a.click();
  };

  const filteredAndSorted = (() => {
    let list = filtered;
    if (nearbyMode && userLocation) {
      list = list.map(m => ({ ...m, _dist: haversine(userLocation.lat, userLocation.lng, m.lat, m.lng) }))
                 .filter(m => m._dist <= 500)
                 .sort((a, b) => a._dist - b._dist);
    } else if (searchMode === "gem" && gemSearch.trim()) {
      // Sort gem results: exact gem array matches first, then name matches, then note matches
      const q = gemSearch.toLowerCase().trim();
      list = [...list].sort((a, b) => {
        const aExact = a.gems.some(g => g.toLowerCase() === q) ? 0 : a.gems.some(g => g.toLowerCase().includes(q)) ? 1 : 2;
        const bExact = b.gems.some(g => g.toLowerCase() === q) ? 0 : b.gems.some(g => g.toLowerCase().includes(q)) ? 1 : 2;
        return aExact - bExact;
      });
    }
    return list;
  })();

  const states = ["ALL", ...Array.from(new Set(MINES.filter(m => !m.country).map(m => m.state))).sort()];
  const countries = ["ALL", "United States", ...Array.from(new Set(MINES.filter(m => m.country).map(m => m.country))).sort()];

  const btn = active => ({
    padding: "5px 10px", fontSize: "clamp(9px, 2vw, 11px)", fontFamily: "inherit", cursor: "pointer",
    border: "1px solid #6b7280", borderRadius: "4px",
    background: active ? "#4b5563" : "#ffffff",
    color: active ? "#ffffff" : "#4b5563",
    fontWeight: active ? "bold" : "normal",
    textTransform: "none", whiteSpace: "nowrap", flexShrink: 0,
  });

  return (
    <div style={{ fontFamily: "Courier New, monospace", background: "#ffffff", color: "#374151", height: "100vh", display: "flex", flexDirection: "column", overflow: "hidden" }}>

      <div style={{ padding: "8px 14px", background: "#ffffff", borderBottom: "2px solid #6b7280", zIndex: 2000, position: "relative" }}>

        <div style={{ display: "flex", alignItems: "center", gap: "6px", marginBottom: "8px", flexWrap: "nowrap", minWidth: 0 }}>
          {/* Title */}
          <div style={{ flexShrink: 0, minWidth: 0 }}>
            <div style={{ fontSize: "clamp(10px, 2.5vw, 13px)", fontWeight: "bold", color: "#4b5563", letterSpacing: "2px", whiteSpace: "nowrap" }}>DIG IT YOURSELF</div>
            <div style={{ fontSize: "8px", color: "#9ca3af", letterSpacing: "1px", whiteSpace: "nowrap", position: "absolute" }}>{MINES.length} SITES WORLDWIDE</div>
          </div>
          <div style={{ flex: 1, minWidth: 0 }} />

          {/* Visited counter */}
          <div style={{ position: "relative" }}>
            <div onClick={() => { setShowVisitedBreakdown(o => !o); setShowSettings(false); setShowHelp(false); }}
              style={{ padding: "3px 8px", background: "#ffffff", border: "1px solid #6b7280", borderRadius: "4px", fontSize: "10px", color: "#4b5563", whiteSpace: "nowrap", cursor: "pointer" }}>
              {visited.size}/{MINES.length} visited
            </div>
            {showVisitedBreakdown && (() => {
              const byRegion = {};
              MINES.forEach(m => {
                const key = m.country ? m.country : (STATE_NAMES[m.state] || m.state || "Unknown");
                if (!byRegion[key]) byRegion[key] = { total: 0, seen: 0 };
                byRegion[key].total++;
                if (visited.has(m.id)) byRegion[key].seen++;
              });
              const sorted = Object.entries(byRegion).filter(([,v]) => v.seen > 0).sort((a,b) => b[1].seen - a[1].seen);
              return (
                <div style={{ position: "absolute", top: "100%", right: 0, marginTop: "4px", zIndex: 3000, background: "#ffffff", border: "1px solid #d1d5db", borderRadius: "6px", boxShadow: "0 4px 12px rgba(0,0,0,0.15)", padding: "8px 12px", minWidth: "180px", maxHeight: "280px", overflowY: "auto", fontSize: "10px", color: "#374151" }}>
                  <div style={{ fontWeight: "bold", letterSpacing: "1px", marginBottom: "6px", color: "#6b7280", fontSize: "9px" }}>VISITED BY REGION</div>
                  {sorted.length === 0 && <div style={{ color: "#9ca3af" }}>None yet</div>}
                  {sorted.map(([region, v]) => (
                    <div key={region} style={{ display: "flex", justifyContent: "space-between", marginBottom: "3px", gap: "12px" }}>
                      <span>{region}</span>
                      <span style={{ color: "#6b7280", flexShrink: 0 }}>{v.seen}/{v.total}</span>
                    </div>
                  ))}
                </div>
              );
            })()}
          </div>

          {/* ? Help button */}
          <div style={{ position: "relative" }}>
            <button onClick={() => { setShowHelp(o => !o); setShowSettings(false); setShowVisitedBreakdown(false); }}
              style={{ width: 26, height: 26, borderRadius: "50%", border: "1px solid #6b7280", background: showHelp ? "#4b5563" : "#ffffff", color: showHelp ? "#ffffff" : "#4b5563", fontSize: "12px", cursor: "pointer", fontFamily: "inherit", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: "bold", textTransform: "none" }}>?</button>
            {showHelp && (
              <div style={{ position: "absolute", top: "100%", right: 0, marginTop: "4px", zIndex: 3000, background: "#ffffff", border: "1px solid #d1d5db", borderRadius: "6px", boxShadow: "0 4px 12px rgba(0,0,0,0.15)", padding: "12px 14px", width: "240px", fontSize: "10px", color: "#374151", lineHeight: "1.6" }}>
                <div style={{ fontWeight: "bold", fontSize: "11px", marginBottom: "8px", color: "#4b5563" }}>How to use</div>
                <div style={{ marginBottom: "6px" }}><b>Search:</b> Filter by state, country, gem type, or price range using the buttons below.</div>
                <div style={{ marginBottom: "6px" }}><b>Markers:</b> Tap any pin to see site details. Circle = fee dig, square = fossil, triangle = shop, grey = public land.</div>
                <div style={{ marginBottom: "6px" }}><b>Visited:</b> Tap the checkmark in a site's detail panel to mark it visited. Your progress is saved.</div>
                <div style={{ marginBottom: "6px" }}><b>Legend:</b> Tap legend rows on the map to filter types on/off.</div>
                <div style={{ marginBottom: "6px" }}><b>☰ Menu:</b> Switch between Dig Map and Mineral Map, show/hide the site list, sort by your location (Near Me), and export your visited sites as a CSV.</div>
                <div style={{ marginBottom: "6px" }}><b>Visited counter:</b> Tap the 0/301 counter to see a breakdown of sites visited by state and country.</div>
                <div><b>Detail panel:</b> Tap a pin to open its details. Tap the map background to close it.</div>
              </div>
            )}
          </div>

          {/* Views ☰ button */}
          <div style={{ position: "relative" }}>
            <button onClick={() => { setShowViews(o => !o); setShowHelp(false); setShowVisitedBreakdown(false); setShowSettings(false); }}
              style={{ width: 26, height: 26, borderRadius: "50%", border: "1px solid #6b7280", background: showViews ? "#4b5563" : "#ffffff", color: showViews ? "#ffffff" : "#4b5563", fontSize: "13px", cursor: "pointer", fontFamily: "inherit", display: "flex", alignItems: "center", justifyContent: "center", textTransform: "none" }}>{"\u2630"}</button>
            {showViews && (
              <div style={{ position: "absolute", top: "100%", right: 0, marginTop: "4px", zIndex: 3000, background: "#ffffff", border: "1px solid #d1d5db", borderRadius: "6px", boxShadow: "0 4px 12px rgba(0,0,0,0.15)", padding: "4px 0", minWidth: "170px", fontSize: "11px", color: "#374151" }}>
                {[
                  { label: "Dig Map", desc: "Fee digs, public land, fossils", action: () => { setViewMode("dig"); setShowViews(false); }, active: viewMode === "dig" },
                  { label: "Mineral Map", desc: "Geological zone overlays", action: () => { setViewMode("mineral"); setShowViews(false); }, active: viewMode === "mineral" },
                  { label: "Site List", desc: "Toggle sidebar list", action: () => { setSidebarOpen(o => !o); }, active: sidebarOpen },
                  { label: "Near Me", desc: nearbyMode ? "On - sorted by distance" : "Sort by your location", action: handleNearby, active: nearbyMode },
                  ...(visited.size > 0 ? [{ label: "Export Visited", desc: "Download as CSV", action: () => { exportVisited(); setShowViews(false); }, active: false }] : []),
                  { label: "Blog", desc: "Rockhounding stories & guides", action: () => { window.open("https://dig-it-yourself-blog.netlify.app", "_blank"); setShowViews(false); }, active: false },
                ].map(({ label, desc, action, active }) => (
                  <div key={label} onClick={action}
                    style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "8px 14px", cursor: "pointer", borderBottom: "1px solid #f3f4f6" }}
                    onMouseEnter={e => e.currentTarget.style.background = "#f9fafb"}
                    onMouseLeave={e => e.currentTarget.style.background = ""}>
                    <div>
                      <div style={{ fontSize: "11px", fontWeight: active ? "bold" : "normal", color: active ? "#4b5563" : "#374151" }}>{label}</div>
                      <div style={{ fontSize: "9px", color: "#9ca3af", marginTop: "1px" }}>{desc}</div>
                    </div>
                    {active && <div style={{ width: 6, height: 6, borderRadius: "50%", background: "#4b5563", marginLeft: 10, flexShrink: 0 }} />}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {viewMode === "dig" && (
          <div style={{ position: "relative" }}>
            <div style={{ display: "flex", gap: "6px", marginBottom: "7px", flexWrap: "wrap" }}>
              <button style={btn(searchMode === "state")} onClick={() => { setSearchMode("state"); setStateFilter("ALL"); }}>{region === "WLD" ? "By Country" : "By State"}</button>
              <button style={btn(searchMode === "country")} onClick={() => { setSearchMode("country"); setStateFilter("ALL"); }}>By Country</button>
              <button style={btn(searchMode === "gem")} onClick={() => setSearchMode("gem")}>By Gem / Fossil</button>
              <button style={btn(searchMode === "price")} onClick={() => setSearchMode("price")}>By Price</button>
              <div style={{ marginLeft: "auto", fontSize: "10px", color: searchMode === "gem" && gemSearch.trim() ? "#4b5563" : "#9ca3af", fontWeight: searchMode === "gem" && gemSearch.trim() ? "bold" : "normal", alignSelf: "center", whiteSpace: "nowrap" }}>
                {nearbyMode ? filteredAndSorted.length + " within 500mi" : filtered.length + " SITE" + (filtered.length !== 1 ? "S" : "")}
              </div>
              {locationError && <div style={{ fontSize: "9px", color: "#ef4444", marginTop: "2px" }}>{locationError}</div>}
            </div>
            {searchMode === "state" && region !== "WLD" && (
              <select value={stateFilter} onChange={e => setStateFilter(e.target.value)}
                style={{ width: "100%", padding: "6px 9px", background: "#ffffff", border: "1px solid #d1d5db", borderRadius: "4px", color: "#374151", fontSize: "12px", fontFamily: "inherit", cursor: "pointer", outline: "none" }}>
                {states.map(s => <option key={s} value={s}>{s === "ALL" ? "All States" : (STATE_NAMES[s] || s) + " (" + s + ")"}</option>)}
              </select>
            )}

            {(searchMode === "country" || (searchMode === "state" && region === "WLD")) && (
              <select value={stateFilter} onChange={e => setStateFilter(e.target.value)}
                style={{ width: "100%", padding: "6px 9px", background: "#ffffff", border: "1px solid #d1d5db", borderRadius: "4px", color: "#374151", fontSize: "12px", fontFamily: "inherit", cursor: "pointer", outline: "none" }}>
                {countries.map(c => <option key={c} value={c}>{c === "ALL" ? "All Countries" : c}</option>)}
              </select>
            )}

            {searchMode === "gem" && (
              <input value={gemSearch} onChange={e => setGemSearch(e.target.value)}
                placeholder="e.g. sapphire, shark teeth, trilobite"
                style={{ width: "100%", padding: "6px 9px", background: "#ffffff", border: "1px solid #d1d5db", borderRadius: "4px", color: "#374151", fontSize: "12px", fontFamily: "inherit", outline: "none", boxSizing: "border-box" }} />
            )}

            {searchMode === "price" && (
              <div style={{ display: "flex", alignItems: "center", gap: "8px", flexWrap: "wrap" }}>
                <span style={{ fontSize: "11px", color: "#6b7280" }}>$</span>
                <input type="number" min="0" value={priceMin} onChange={e => setPriceMin(e.target.value)}
                  placeholder="Min" style={{ width: "70px", padding: "5px 7px", border: "1px solid #d1d5db", borderRadius: "4px", fontSize: "12px", fontFamily: "inherit", outline: "none" }} />
                <span style={{ fontSize: "11px", color: "#6b7280" }}>to</span>
                <input type="number" min="0" value={priceMax} onChange={e => setPriceMax(e.target.value)}
                  placeholder="Max" style={{ width: "70px", padding: "5px 7px", border: "1px solid #d1d5db", borderRadius: "4px", fontSize: "12px", fontFamily: "inherit", outline: "none" }} />
                <label style={{ display: "flex", alignItems: "center", gap: "5px", fontSize: "11px", color: "#4b5563", cursor: "pointer", userSelect: "none" }}>
                  <input type="checkbox" checked={includeUncertain} onChange={e => setIncludeUncertain(e.target.checked)} style={{ cursor: "pointer" }} />
                  Include uncertain / contact pricing
                </label>
              </div>
            )}
          </div>
        )}
      </div>

      <div style={{ flex: 1, display: "flex", overflow: "hidden", position: "relative" }}>

        {viewMode === "mineral" ? (
          <div style={{ flex: 1, position: "relative" }}>
            <MineralMapComponent mines={MINES} region={region} />
            <div style={{ position: "absolute", bottom: 16, left: 10, background: "rgba(255,255,255,0.97)", border: "1px solid #d1d5db", borderRadius: "6px", fontSize: "10px", zIndex: 999, maxHeight: "60vh", overflow: "hidden" }}>
              <div onClick={() => setLegendOpen(o => !o)} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "6px 10px", cursor: "pointer", borderBottom: legendOpen ? "1px solid #e5e7eb" : "none" }}>
                <span style={{ color: "#4b5563", fontWeight: "bold", letterSpacing: "1px" }}>GEM CATEGORIES</span>
                <span style={{ color: "#9ca3af", marginLeft: "12px", fontSize: "11px" }}>{legendOpen ? "▲" : "▼"}</span>
              </div>
              {legendOpen && (
                <div style={{ padding: "6px 10px 8px", overflowY: "auto", maxHeight: "55vh" }}>
                  {GEM_CATEGORIES.map(cat => (
                    <div key={cat.name} style={{ display: "flex", alignItems: "center", gap: "6px", marginBottom: "4px" }}>
                      <div style={{ width: 14, height: 14, borderRadius: "3px", background: cat.color, border: "1px solid rgba(0,0,0,0.15)", flexShrink: 0 }} />
                      <span style={{ color: "#374151" }}>{cat.name}</span>
                    </div>
                  ))}
                  <div style={{ marginTop: "8px", paddingTop: "6px", borderTop: "1px solid #e5e7eb", fontSize: "9px", color: "#9ca3af", lineHeight: "1.6" }}>
                    Colored zones show actual geological regions where each gem is known to occur (USGS surveys). Zones may overlap where multiple gems share a formation. Dots = individual public dig sites.
                  </div>
                </div>
              )}
            </div>
          </div>
        ) : (
          <div style={{ flex: 1, display: "flex", overflow: "hidden" }}>
            <div style={{ flex: 1, position: "relative" }} onClick={e => { if (e.target === e.currentTarget) setSelected(null); }}>
              <MapComponent mines={filteredAndSorted} visited={visited} onMineClick={setSelected} zoomState={searchMode === "state" ? stateFilter : "ALL"} region={region} />
              <div style={{ position: "absolute", bottom: 22, left: 10, background: "rgba(255,255,255,0.95)", border: "1px solid #d1d5db", borderRadius: "6px", fontSize: "10px", zIndex: 999, overflow: "hidden" }}>
                <div onClick={() => setLegendOpen(o => !o)} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "5px 10px", cursor: "pointer", borderBottom: legendOpen ? "1px solid #e5e7eb" : "none" }}>
                  <span style={{ color: "#4b5563", fontWeight: "bold" }}>LEGEND</span>
                  <span style={{ color: "#9ca3af", marginLeft: "12px", fontSize: "11px" }}>{legendOpen ? "▲" : "▼"}</span>
                </div>
                {legendOpen && (
                  <div style={{ padding: "5px 10px 7px" }}>
                    {[
                      { key: "dig", icon: <div style={{ width: 12, height: 12, borderRadius: "50%", background: "#ffffff", border: "2px solid #4b5563", flexShrink: 0 }} />, label: "Fee dig" },
                      { key: "publicLand", icon: <div style={{ width: 12, height: 12, borderRadius: "50%", background: "#e5e7eb", border: "2px solid #9ca3af", flexShrink: 0 }} />, label: "Public land" },
                      { key: "fossil", icon: <div style={{ width: 12, height: 12, borderRadius: "2px", background: "#ffffff", border: "2px solid #4b5563", flexShrink: 0 }} />, label: "Fossil site" },
                      { key: "shop", icon: <svg width="14" height="12" viewBox="0 0 14 12" style={{ flexShrink: 0 }}><polygon points="7,1 13,11 1,11" fill="#ffffff" stroke="#4b5563" strokeWidth="1.5"/></svg>, label: "Shop/Workshop" },
                    ].map(({ key, icon, label }) => (
                      <div key={key} onClick={() => setTypeFilters(f => ({ ...f, [key]: !f[key] }))}
                        style={{ display: "flex", alignItems: "center", gap: "5px", marginBottom: "3px", cursor: "pointer", opacity: typeFilters[key] ? 1 : 0.35, userSelect: "none" }}>
                        {icon}
                        <span style={{ textDecoration: typeFilters[key] ? "none" : "line-through" }}>{label}</span>
                      </div>
                    ))}
                    <div style={{ display: "flex", alignItems: "center", gap: "5px", marginTop: "1px" }}>
                      <div style={{ width: 12, height: 12, borderRadius: "50%", background: "#6b7280", border: "2px solid #374151", flexShrink: 0 }} />
                      <span>Visited</span>
                    </div>
                  </div>
                )}
              </div>
              <div style={{ position: "absolute", top: 10, right: 10, background: "rgba(255,255,255,0.92)", border: "1px solid #d1d5db", borderRadius: "5px", padding: "4px 9px", fontSize: "10px", zIndex: 999, color: "#6b7280" }}>
                {nearbyMode ? filteredAndSorted.length + " within 500mi" : filtered.length + " SITE" + (filtered.length !== 1 ? "S" : "")}
              </div>
              {locationError && <div style={{ fontSize: "9px", color: "#ef4444", marginTop: "2px" }}>{locationError}</div>}
            </div>

            {sidebarOpen && (
              <div style={{ width: "260px", background: "#ffffff", borderLeft: "2px solid #d1d5db", display: "flex", flexDirection: "column", overflowY: "auto" }}>
                <div style={{ padding: "5px 10px", borderBottom: "1px solid #f9fafb", fontSize: "9px", color: "#6b7280", letterSpacing: "1px", background: "#f9fafb", flexShrink: 0 }}>
                  {filtered.length} OF {MINES.length} MINES
                </div>
                {filtered.map(mine => (
                  <div key={mine.id} onClick={() => setSelected(mine)}
                    style={{ padding: "8px 10px", cursor: "pointer", borderBottom: "1px solid #f9fafb", background: selected?.id === mine.id ? "#f9fafb" : "transparent", transition: "background 0.1s" }}
                    onMouseEnter={e => e.currentTarget.style.background = "#f9fafb"}
                    onMouseLeave={e => e.currentTarget.style.background = selected?.id === mine.id ? "#f9fafb" : "transparent"}>
                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                      <div style={{ fontSize: "11px", fontWeight: "bold", color: "#4b5563", flex: 1, lineHeight: "1.3" }}>{mine.name}</div>
                      {visited.has(mine.id) && <span style={{ fontSize: "10px", marginLeft: "4px", color: "#6b7280", flexShrink: 0 }}>{"\u2714"}</span>}
                    </div>
                    <div style={{ fontSize: "9px", color: "#9ca3af", marginTop: "1px" }}>{mine.country ? mine.country : (STATE_NAMES[mine.state] || mine.state)}</div>
                    <div style={{ fontSize: "9px", color: "#6b7280", marginTop: "2px", lineHeight: "1.3" }}>{mine.gems.slice(0, 3).join(" \u00b7 ")}{mine.gems.length > 3 ? " +" + (mine.gems.length - 3) : ""}</div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
      </div>

      {selected && (
        <div style={{ position: "fixed", bottom: 0, left: 0, right: 0, background: "linear-gradient(0deg,#ffffff,#f9fafb)", border: "2px solid #d1d5db", borderBottom: "none", borderRadius: "16px 16px 0 0", padding: "14px 18px 22px", zIndex: 2000, maxHeight: "56vh", overflowY: "auto", boxShadow: "0 -6px 40px rgba(0,0,0,0.1)" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "12px" }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: "16px", fontWeight: "bold", color: "#4b5563", lineHeight: "1.3", marginBottom: "2px" }}>{selected.name}</div>
              <div style={{ fontSize: "9px", color: "#9ca3af", letterSpacing: "2px" }}>{STATE_NAMES[selected.state] || selected.state}</div>
            </div>
            <div style={{ display: "flex", gap: "7px", alignItems: "center", marginLeft: "10px" }}>
              <button onClick={() => toggleVisited(selected.id)} style={{
                padding: "6px 12px",
                background: visited.has(selected.id) ? "#6b7280" : "#f9fafb",
                border: "1px solid " + (visited.has(selected.id) ? "#374151" : "#d1d5db"),
                borderRadius: "5px", color: visited.has(selected.id) ? "#ffffff" : "#4b5563",
                fontSize: "10px", cursor: "pointer", fontFamily: "inherit", fontWeight: "bold", letterSpacing: "1px", whiteSpace: "nowrap"
              }}>
                {visited.has(selected.id) ? "VISITED" : "+ MARK VISITED"}
              </button>
              <button onClick={() => setSelected(null)} style={{ width: 25, height: 25, borderRadius: "50%", background: "#f9fafb", border: "1px solid #d1d5db", color: "#4b5563", cursor: "pointer", fontSize: "12px", display: "flex", alignItems: "center", justifyContent: "center" }}>x</button>
            </div>
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))", gap: "9px" }}>
            <div style={{ background: "#f9fafb", border: "1px solid #e5e7eb", borderRadius: "7px", padding: "8px 11px" }}>
              <div style={{ fontSize: "8px", color: "#6b7280", letterSpacing: "2px", marginBottom: "3px" }}>ADDRESS</div>
              <div style={{ fontSize: "11px", lineHeight: "1.5", color: "#374151" }}>{selected.address}</div>
            </div>
            <div style={{ background: "#f9fafb", border: "1px solid #e5e7eb", borderRadius: "7px", padding: "8px 11px" }}>
              <div style={{ fontSize: "8px", color: "#6b7280", letterSpacing: "2px", marginBottom: "3px" }}>PRICING</div>
              <div style={{ fontSize: "11px", color: "#374151" }}>{selected.pricing || "Contact mine for current pricing"}</div>
            </div>
            <div style={{ background: "#f9fafb", border: "1px solid #e5e7eb", borderRadius: "7px", padding: "8px 11px", gridColumn: "1 / -1" }}>
              <div style={{ fontSize: "8px", color: "#6b7280", letterSpacing: "2px", marginBottom: "6px" }}>WHAT YOU CAN FIND</div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: "5px" }}>
                {selected.gems.map(gem => (
                  <span key={gem} style={{ padding: "2px 8px", borderRadius: "12px", background: "#f9fafb", border: "1px solid #d1d5db", fontSize: "10px", color: "#4b5563" }}>{gem}</span>
                ))}
              </div>
            </div>
            {selected.note && (
              <div style={{ background: "#f9fafb", border: "1px solid #d1d5db", borderRadius: "7px", padding: "8px 11px", gridColumn: "1 / -1" }}>
                <div style={{ fontSize: "8px", color: "#4b5563", letterSpacing: "2px", marginBottom: "3px" }}>NOTES</div>
                <div style={{ fontSize: "11px", color: "#374151", lineHeight: "1.5" }}>{selected.note}</div>
              </div>
            )}
            {selected.url && (
              <div style={{ gridColumn: "1 / -1", marginTop: "2px" }}>
                <a href={selected.url} target="_blank" rel="noopener noreferrer"
                  style={{ display: "inline-block", fontSize: "10px", color: "#4b5563", border: "1px solid #6b7280", borderRadius: "4px", padding: "4px 10px", textDecoration: "none", letterSpacing: "1px", fontFamily: "inherit" }}>
                  VISIT WEBSITE &rarr;
                </a>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
